func NewPortMux(port int, managerHost string) *PortMux {
	pMux := &PortMux{
		managerHost:	managerHost,
		port:		port,
		clientConn:	make(chan *PortConn),
		httpConn:	make(chan *PortConn),
		httpsConn:	make(chan *PortConn),
		managerConn:	make(chan *PortConn),
	}
	pMux.Start()
	return pMux
}
